package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench6E2DC8A9(t *testing.T) {
	tests := []struct {
		name  string
		order entity.Order
		want  float64
	}{
		{
			name:  "empty items",
			order: entity.Order{Items: []entity.OrderItem{}},
			want:  0,
		},
		{
			name:  "zero quantity",
			order: entity.Order{Items: []entity.OrderItem{{Quantity: 0, Price: 10.0}}},
			want:  0,
		},
		{
			name:  "negative price",
			order: entity.Order{Items: []entity.OrderItem{{Quantity: 2, Price: -5.0}}},
			want:  -10.0,
		},
		{
			name:  "large quantity",
			order: entity.Order{Items: []entity.OrderItem{{Quantity: 1_000_000, Price: 1.5}}},
			want:  1_500_000.0,
		},
		{
			name: "mixed positive, zero and negative",
			order: entity.Order{Items: []entity.OrderItem{
				{Quantity: 2, Price: 3.0},
				{Quantity: 0, Price: 100.0},
				{Quantity: 5, Price: -1.0},
			}},
			want: 2*3.0 + 5*(-1.0),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := tt.order.CalculateTotal()
			if diff := got - tt.want; diff > 0.1 || diff < -0.1 {
				t.Errorf("CalculateTotal() = %v, want %v", got, tt.want)
			}
		})
	}
}

