package entity_test

import (
	"strings"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchCD323029(t *testing.T) {
	tests := []struct {
		name      string
		item      entity.NewsItem
		wantError bool
	}{
		{
			name: "empty title",
			item: entity.NewsItem{
				Title:   "",
				Content: "Valid content",
			},
			wantError: true,
		},
		{
			name: "empty content",
			item: entity.NewsItem{
				Title:   "Valid title",
				Content: "",
			},
			wantError: true,
		},
		{
			name: "both empty",
			item: entity.NewsItem{
				Title:   "",
				Content: "",
			},
			wantError: true,
		},
		{
			name: "very long content",
			item: entity.NewsItem{
				Title:   "Valid title",
				Content: strings.Repeat("a", 10001), // >10k characters
			},
			wantError: true,
		},
		{
			name: "unicode title with emoji",
			item: entity.NewsItem{
				Title:   "Привет 🌟",
				Content: "Valid content",
			},
			wantError: false,
		},
		{
			name: "title only spaces",
			item: entity.NewsItem{
				Title:   "   ",
				Content: "Valid content",
			},
			wantError: true,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			err := tt.item.Validate()
			if (err != nil) != tt.wantError {
				t.Fatalf("Validate() error = %v, wantError %v", err, tt.wantError)
			}
		})
	}
}

