package entity_test

// CHOICE: Product.ApplyDiscount — edge cases for discount bounds and floating‑point precision

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchC548CC64(t *testing.T) {
	const tolerance = 0.1

	tests := []struct {
		name       string
		startPrice float64
		discount   float64
		wantPrice  float64
		wantErr    bool
	}{
		{
			name:       "normal discount 10%",
			startPrice: 100.0,
			discount:   10.0,
			wantPrice:  90.0,
			wantErr:    false,
		},
		{
			name:       "zero discount",
			startPrice: 55.5,
			discount:   0.0,
			wantPrice:  55.5,
			wantErr:    false,
		},
		{
			name:       "full discount 100%",
			startPrice: 42.0,
			discount:   100.0,
			wantPrice:  0.0,
			wantErr:    false,
		},
		{
			name:       "negative discount (invalid)",
			startPrice: 30.0,
			discount:   -5.0,
			wantPrice:  30.0, // price should remain unchanged
			wantErr:    true,
		},
		{
			name:       "over‑100% discount (invalid)",
			startPrice: 80.0,
			discount:   150.0,
			wantPrice:  80.0, // price should remain unchanged
			wantErr:    true,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Arrange
			p := &entity.Product{
				Price: tt.startPrice,
			}

			// Act
			err := p.ApplyDiscount(tt.discount)

			// Assert error expectation
			if (err != nil) != tt.wantErr {
				t.Fatalf("ApplyDiscount() error = %v, wantErr %v", err, tt.wantErr)
			}

			// If an error was expected, we don't check the price further
			if tt.wantErr {
				if math.Abs(p.Price-tt.wantPrice) > tolerance {
					t.Fatalf("price changed on error: got %v, want %v (tolerance %.2f)", p.Price, tt.wantPrice, tolerance)
				}
				return
			}

			// Verify resulting price within tolerance
			if math.Abs(p.Price-tt.wantPrice) > tolerance {
				t.Fatalf("ApplyDiscount() price = %v, want %v (tolerance %.2f)", p.Price, tt.wantPrice, tolerance)
			}
		})
	}
}
